const { PrismaClient } = require('@prisma/client');
const prisma = new PrismaClient();
const path = require('path');

async function main() {
  console.log('--- Seeding EEE Students ---');

  // Resolve EEE Department
  let eeeDept = await prisma.department.findFirst({
    where: { 
      OR: [
        { code: 'EEE' },
        { name: { contains: 'Electrical and Electronics' } }
      ]
    }
  });

  if (!eeeDept) {
    console.log('Creating EEE Department...');
    eeeDept = await prisma.department.create({
      data: {
        name: 'Electrical and Electronics Engineering',
        code: 'EEE',
        sections: 'A,B',
        years: '2,3,4'
      }
    });
  }

  const academicYear = await prisma.academicYear.findFirst({ where: { isActive: true } }) || { id: 1 };

  // Helper to ensure section exists
  async function getSectionId(name, semester) {
    let sec = await prisma.section.findFirst({
      where: { name, semester, departmentId: eeeDept.id }
    });
    if (!sec) {
      sec = await prisma.section.create({
        data: { name, semester, type: 'DEPARTMENT', departmentId: eeeDept.id, academicYearId: academicYear.id }
      });
    }
    return sec.id;
  }

  const sectionAId = await getSectionId('A', 5); // 3rd Year EEE

  const students = [
    {
      rollNo: "E122EEE001",
      registerNumber: "812422105001",
      name: "ARJUN V",
      department: "EEE",
      departmentId: eeeDept.id,
      year: 3,
      semester: 5,
      currentSemester: 5,
      section: "A",
      sectionId: sectionAId,
      batch: "2022-2026",
      batchYear: "2022",
      admissionYear: "2022",
      gender: "MALE",
      dateOfBirth: "12-05-2004",
      phoneNumber: "9876543210",
      email: "arjun.eee@college.edu",
      photo: "data:image/png;base64,",
      fatherName: "VARADARAJAN",
      motherName: "LAKSHMI",
      address: "123, Gandhi Nagar, Coimbatore",
      status: "ACTIVE"
    },
    {
      rollNo: "E122EEE002",
      registerNumber: "812422105002",
      name: "BHAVANI R",
      department: "EEE",
      departmentId: eeeDept.id,
      year: 3,
      semester: 5,
      currentSemester: 5,
      section: "A",
      sectionId: sectionAId,
      batch: "2022-2026",
      batchYear: "2022",
      admissionYear: "2022",
      gender: "FEMALE",
      dateOfBirth: "24-03-2004",
      phoneNumber: "9876543211",
      email: "bhavani.eee@college.edu",
      photo: "data:image/png;base64,",
      fatherName: "RAJAMANICKAM",
      motherName: "SARASWATHI",
      address: "45, Main Road, Erode",
      status: "ACTIVE"
    },
    {
      rollNo: "E122EEE003",
      registerNumber: "812422105003",
      name: "CHANDRAN K",
      department: "EEE",
      departmentId: eeeDept.id,
      year: 3,
      semester: 5,
      currentSemester: 5,
      section: "A",
      sectionId: sectionAId,
      batch: "2022-2026",
      batchYear: "2022",
      admissionYear: "2022",
      gender: "MALE",
      dateOfBirth: "08-11-2003",
      phoneNumber: "9876543212",
      email: "chandran.eee@college.edu",
      photo: "data:image/png;base64,",
      fatherName: "KANDASAMY",
      motherName: "VIJAYA",
      address: "7, Cross Street, Madurai",
      status: "ACTIVE"
    }
  ];

  for (const s of students) {
    await prisma.student.upsert({
      where: { rollNo: s.rollNo },
      update: s,
      create: s
    });
    console.log(`Student ${s.name} (${s.rollNo}) processed.`);
  }

  console.log('--- EEE Seeding Complete ---');
}

main()
  .catch(e => {
    console.error(e);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });
